mapper.select:
SELECT a.id, a.store_id, a.p_id, a.s_id, a.uplevel, a.distribution_rule, a.rules_set, a.add_time, a.recycle, a.pv, a.img, a.imgurl, a.attribute, a.num, a.min_inventory, a.price, a.product_title, a.costprice, a.NAME FROM ( SELECT , b.img, c.imgurl, b.attribute, b.num, b.recycle as brecycle, b.min_inventory, b.price, c.product_title, c.status as cstatus, c.num as cnum, b.costprice, m.NAME, ROW_NUMBER() over (partition by a.p_id ) AS top FROM lkt_distribution_goods AS a LEFT JOIN lkt_configure AS b ON a.s_id = b.id LEFT JOIN lkt_product_list AS c ON a.p_id = c.id LEFT JOIN lkt_mch AS m ON c.mch_id = m.id
add_time ${add_time_sort}, b.price ${price_sort}, ${any_key} ${any_sort},
) AS a where a.top <2 limit #{pageStart},#{pageEnd}

select a.*,b.product_title, d.name mchName, d.id mchId from lkt_configure as a left join lkt_product_list as b on a.pid = b.id left join lkt_mch as d on b.mch_id = d.id
add_date ${add_date_sort},
limit #{pageStart},#{pageEnd}
